arguments.file_text:
namespace sv_0e92c7b4fcd041ae8f2b088c2cad6535.Models;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

using sv_0e92c7b4fcd041ae8f2b088c2cad6535.Models;

namespace sv_0e92c7b4fcd041ae8f2b088c2cad6535.Services;

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_0e92c7b4fcd041ae8f2b088c2cad6535.Models
@using sv_0e92c7b4fcd041ae8f2b088c2cad6535.Services
@using sv_0e92c7b4fcd041ae8f2b088c2cad6535.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-layout">
    <CatalogSidebar Categories="_categories"
                    OnFilterApplied="HandleFilterApplied" />

    <main class="catalog-main">
        @if (_loading)
        {
            <div class="catalog-status">
                <p>Loading products…</p>
            </div>
        }
        else if (_error is not null)
        {
            <div class="catalog-status error">
                <p>Something went wrong: @_error</p>
                <button @onclick="LoadProductsAsync">Retry</button>
            </div>
        }
        else if (_result is null || _result.Items.Count == 0)
        {
            <div class="catalog-status">
                <p>No products found. Try adjusting your filters.</p>
            </div>
        }
        else
        {
            <CatalogToolbar SortBy="@_sortBy"
                            Page="_currentPage"
                            PageSize="PageSize"
                            TotalCount="_result.TotalCount"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="_result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination CurrentPage="_currentPage"
                               TotalPages="_totalPages"
                               OnPageChanged="HandlePageChanged" />
        }
    </main>
</div>

@code {
    private const int PageSize = 12;

    private List<string> _categories = [];
    private PagedResult<Product>? _result;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private int _totalPages = 1;
    private bool _loading = true;
    private string? _error;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            await Task.WhenAll(categoriesTask, productsTask);

            _categories = categoriesTask.Result;
            _result = productsTask.Result;
            UpdateTotalPages();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task LoadProductsAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            UpdateTotalPages();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadProductsAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        await OnAddToCart.InvokeAsync(product);
    }

    private void UpdateTotalPages()
    {
        if (_result is not null && _result.PageSize > 0)
        {
            _totalPages = Math.Max(1, (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize));
        }
    }
}

.catalog-layout {
    display: flex;
    min-height: calc(100vh - 4rem);
}

.catalog-layout > :first-child {
    width: 25%;
    min-width: 220px;
    flex-shrink: 0;
}

.catalog-main {
    width: 75%;
    flex: 1;
    padding: 1.5rem;
}

.catalog-status {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 4rem 2rem;
    color: #777;
    font-size: 1.1rem;
    gap: 1rem;
}

.catalog-status.error {
    color: #c00;
}

.catalog-status button {
    padding: 0.5rem 1.5rem;
    background: #4a90d9;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-weight: 600;
}

