toolArgs.file_text:
.catalog-layout {
    display: flex;
    min-height: calc(100vh - 4rem);
}

.catalog-layout > :first-child {
    width: 25%;
    min-width: 220px;
    flex-shrink: 0;
}

.catalog-main {
    width: 75%;
    flex: 1;
    padding: 1.5rem;
}

.catalog-status {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 4rem 2rem;
    color: #777;
    font-size: 1.1rem;
    gap: 1rem;
}

.catalog-status.error {
    color: #c00;
}

.catalog-status button {
    padding: 0.5rem 1.5rem;
    background: #4a90d9;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-weight: 600;
}

